"""MSE, RMSE, SNR (дБ), корреляция Пирсона, compute_all."""from __future__ import annotationsfrom typing import Unionimport numpy as npfrom numpy.typing import NDArrayfrom ..core.types import Metrics, SignalArrayLike = Union[NDArray[np.float64], Signal]def _as_array(a: ArrayLike, name: str) -> NDArray[np.float64]:    if isinstance(a, Signal):        arr = a.x    else:        arr = np.asarray(a, dtype=np.float64)    if arr.ndim != 1:        raise ValueError(f"{name}: expected 1-D array, got ndim={arr.ndim}")    if arr.size == 0:        raise ValueError(f"{name}: empty array")    if not np.all(np.isfinite(arr)):        raise ValueError(f"{name}: contains NaN/Inf")    return arr.astype(np.float64, copy=False)def _pair(ref: ArrayLike, est: ArrayLike) -> tuple[NDArray[np.float64], NDArray[np.float64]]:    r = _as_array(ref, "ref")    e = _as_array(est, "est")    if r.shape != e.shape:        raise ValueError(f"shape mismatch: ref={r.shape}, est={e.shape}")    return r, edef mse(ref: ArrayLike, est: ArrayLike) -> float:    r, e = _pair(ref, est)    diff = r - e    return float(np.mean(diff * diff))def rmse(ref: ArrayLike, est: ArrayLike) -> float:    return float(np.sqrt(mse(ref, est)))def snr_db(ref: ArrayLike, est: ArrayLike) -> float:    r, e = _pair(ref, est)    p_ref = float(np.mean(r * r))    err = r - e    p_err = float(np.mean(err * err))    if p_err == 0.0:        return float("inf")    if p_ref == 0.0:        raise ValueError("snr_db: reference has zero power while error is nonzero — "                         "SNR is undefined")    return float(10.0 * np.log10(p_ref / p_err))def correlation(ref: ArrayLike, est: ArrayLike) -> float:    r, e = _pair(ref, est)    r_std = float(np.std(r))    e_std = float(np.std(e))    if r_std == 0.0 or e_std == 0.0:        return float("nan")    c = np.corrcoef(r, e)[0, 1]    return float(c)def compute_all(clean: ArrayLike, noisy: ArrayLike, restored: ArrayLike) -> Metrics:    c = _as_array(clean, "clean")    n = _as_array(noisy, "noisy")    x = _as_array(restored, "restored")    if not (c.shape == n.shape == x.shape):        raise ValueError(            f"shape mismatch: clean={c.shape}, noisy={n.shape}, restored={x.shape}"        )    m_mse = mse(c, x)    m_rmse = float(np.sqrt(m_mse))    snr_before = snr_db(c, n)    snr_after = snr_db(c, x)    return Metrics(        mse=m_mse, rmse=m_rmse,        snr_before_db=snr_before, snr_after_db=snr_after,        snr_improvement_db=snr_after - snr_before,        correlation=correlation(c, x),    )